      <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n      </div>\n      <div>\n        <div class="evt-log-item-label">สถานที่</div>\n        <div class="evt-log-item-value">กรุงเทพฯ ประเทศไทย (รายละเอียดสถานที่จะส่งหลังลงทะเบียน)</div>\n      </div>\n    </div>\n\n    <div class="evt-log-item">\n      <div class="evt-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>\n      </div>\n      <div>\n        <div class="evt-log-item-label">ค่าใช้จ่าย</div>\n        <div class="evt-log-item-value">ฟรี (สนับสนุนโดย DigiWin Thailand)</div>\n      </div>\n    </div>\n\n    <div class="evt-log-item">\n      <div class="evt-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>\n      </div>\n      <div>\n        <div class="evt-log-item-label">ภาษา</div>\n        <div class="evt-log-item-value">นำเสนอเป็นภาษาไทย พร้อมเอกสารภาษาอังกฤษ</div>\n      </div>\n    </div>\n\n    <div class="evt-log-item">\n      <div class="evt-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>\n      </div>\n      <div>\n        <div class="evt-log-item-label">สิ่งที่ต้องนำมา</div>\n        <div class="evt-log-item-value">แนะนำให้นำแล็ปท็อปมาสำหรับเซสชันลงมือปฏิบัติ ข้อมูลตัวอย่างจัดเตรียมให้</div>\n      </div>\n    </div>\n\n    <div class="evt-log-item">\n      <div class="evt-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="1" y="3" width="15" height="13"/><polygon points="16 8 20 8 23 11 23 16 16 16 16 8"/><circle cx="5.5" cy="18.5" r="2.5"/><circle cx="18.5" cy="18.5" r="2.5"/></svg>\n      </div>\n      <div>\n        <div class="evt-log-item-label">ที่จอดรถ</div>\n        <div class="evt-log-item-value">มีที่จอดรถที่สถานที่จัดงาน (รายละเอียดจะส่งหลังลงทะเบียน)</div>\n      </div>\n    </div>\n\n    <div class="evt-log-item">\n      <div class="evt-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M18 8h1a4 4 0 010 8h-1"/><path d="M2 8h16v9a4 4 0 01-4 4H6a4 4 0 01-4-4V8z"/><line x1="6" y1="1" x2="6" y2="4"/><line x1="10" y1="1" x2="10" y2="4"/><line x1="14" y1="1" x2="14" y2="4"/></svg>\n      </div>\n      <div>\n        <div class="evt-log-item-label">อาหารกลางวัน</div>\n        <div class="evt-log-item-value">รวมอยู่ — อาหารกลางวัน Networking และพักดื่มกาแฟตลอดวัน</div>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Registration CTA"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Registration CTA: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Registration CTA: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-reg-section">\n  <h2>จองที่นั่งของคุณ</h2>\n  <p class="evt-reg-meta">วันเสาร์ที่ 15 มีนาคม 2026 &middot; กรุงเทพฯ &middot; จำกัด 30 ท่าน</p>\n  \n  <a href="/th/demo/" class="evt-reg-cta">\n    ลงทะเบียนตอนนี้\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n  <p class="evt-reg-secondary">มาวันนี้ไม่ได้? <a href="/th/demo/">ลงทะเบียนแสดงความสนใจ</a> and we\'ll notify you of the next session.</p>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Events: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="evt-rel-section">\n  <div class="evt-rel-inner">\n    <span class="evt-rel-label">กิจกรรมที่กำลังจะมาถึง</span>\n    <h2 class="evt-rel-title">เรียนรู้ต่อเนื่อง</h2>\n    <div class="evt-rel-grid">\n      \n    <div class="evt-rel-card">\n      <div class="evt-rel-card-border" style="background:#b45309"></div>\n      <div class="evt-rel-card-body">\n        <span class="evt-rel-badge" style="color:#b45309;background:rgba(180,83,9,0.12)">เยี่ยมชมโรงงาน</span>\n        <h3>Live Factory Tour: See DigiWin MES in Action</h3>\n        <div class="evt-rel-meta">\n          <div class="evt-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 8, 2026\n          </div>\n          <div class="evt-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            EEC Industrial Zone\n          </div>\n        </div>\n        <a href="/news/events/factory-tour-mes/" class="evt-rel-link" style="color:#b45309">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="evt-rel-card">\n      <div class="evt-rel-card-border" style="background:#6d28d9"></div>\n      <div class="evt-rel-card-body">\n        <span class="evt-rel-badge" style="color:#6d28d9;background:rgba(109,40,217,0.12)">งานแสดงสินค้า</span>\n        <h3>Manufacturing Expo 2026: DigiWin Thailand Booth</h3>\n        <div class="evt-rel-meta">\n          <div class="evt-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 20–22, 2026\n          </div>\n          <div class="evt-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            BITEC, Bangkok\n          </div>\n        </div>\n        <a href="/news/events/manufacturing-expo-2026/" class="evt-rel-link" style="color:#6d28d9">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="evt-rel-card">\n      <div class="evt-rel-card-border" style="background:#0369a1"></div>\n      <div class="evt-rel-card-body">\n        <span class="evt-rel-badge" style="color:#0369a1;background:rgba(3,105,161,0.12)">สัมมนา</span>\n        <h3>Production Transparency: From Paper Reports to Real-Time Dashboards</h3>\n        <div class="evt-rel-meta">\n          <div class="evt-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            April 10, 2026\n          </div>\n          <div class="evt-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            Bangkok, Thailand\n          </div>\n        </div>\n        <a href="/news/events/production-transparency-seminar/" class="evt-rel-link" style="color:#0369a1">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100790;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100790 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100790, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === EVENT HERO === */\n.evt-hero-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:140px 24px 80px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.evt-hero-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.evt-hero-section>*{position:relative;z-index:2}\n.evt-hero-back{display:inline-flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:500;color:rgba(255,255,255,0.85);text-decoration:none;margin-bottom:24px;transition:color 0.3s ease}\n.evt-hero-back:hover{color:rgba(255,255,255,0.9)}\n.evt-hero-badge{display:inline-flex;align-items:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:1.5px;color:#15803d;background:rgba(21,128,61,0.15);padding:6px 18px;border:1px solid rgba(21,128,61,0.3);border-radius:50px;margin-bottom:20px}\n.evt-hero-section h1{font-family:\'Noto Sans\',sans-serif;font-size:clamp(28px,4.5vw,44px);font-weight:700;color:#fff;line-height:1.2;max-width:800px;margin:0 auto 20px;padding:0}\n.evt-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0 auto 40px;padding:0}\n.evt-hero-facts{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;max-width:700px;margin:0 auto 40px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:16px;padding:24px}\n.evt-hero-fact{text-align:center}\n.evt-hero-fact-icon{margin-bottom:8px}\n.evt-hero-fact-icon svg{stroke:#15803d}\n.evt-hero-fact-value{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff}\n.evt-hero-fact-label{font-family:\'Noto Sans\',sans-serif;font-size:13px;color:rgba(255,255,255,0.85)}\n.evt-hero-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff;background:#15803d;padding:16px 40px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(21,128,61,0.4)}\n.evt-hero-cta:hover{background:rgb(68,153,100);transform:translateY(-2px);box-shadow:0 8px 24px rgba(21,128,61,0.3)}\n\n.et_pb_section .evt-hero-section h1{-webkit-font-smoothing:auto !important;line-height:1.2 !important;max-width:800px !important;margin:0 auto 20px !important;padding:0 !important}\n.et_pb_section .evt-hero-subtitle{-webkit-font-smoothing:auto !important}\n.et_pb_section .evt-hero-fact-value{-webkit-font-smoothing:auto !important;line-height:25.6px !important;margin-bottom:4px !important}\n.et_pb_section .evt-hero-fact-label{-webkit-font-smoothing:auto !important;line-height:20.8px !important}\n.et_pb_section .evt-hero-badge{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .evt-hero-cta{-webkit-font-smoothing:auto !important;line-height:25.6px !important}\n.et_pb_section .evt-hero-back{-webkit-font-smoothing:auto !important}\n.evt-hero-superd{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.15;pointer-events:none;z-index:0}\n\n@media(max-width:768px){\n  .evt-hero-section{padding:120px 20px 60px}\n  .evt-hero-facts{grid-template-columns:repeat(2,1fr);gap:20px}\n}\n@media(max-width:480px){\n  .evt-hero-facts{grid-template-columns:1fr}\n  .evt-hero-cta{width:100%;justify-content:center}\n}\n@media(prefers-reduced-motion:reduce){.evt-hero-section *{transition:none !important}}\n/* === THAI FONT OVERRIDE (evt-hero) === */\n.evt-hero-badge, .evt-hero-title, .evt-hero-subtitle,\n.evt-hero-fact-value, .evt-hero-fact-label,\n.evt-hero-btn, .evt-hero-back-link {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* === THE PROBLEM === */\n.evt-prob-section{background:#fff;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.evt-prob-inner{text-align:center;max-width:800px;margin:0 auto 40px}\n.evt-prob-label{font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#15803d;display:block;margin-bottom:16px}\n.evt-prob-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.25;margin:0 0 16px;padding:0}\n.evt-prob-body{max-width:800px;margin:0 auto}\n.evt-prob-body p{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#333;line-height:1.8;margin:0 0 24px;padding:0}\n.evt-prob-body strong{font-weight:600;color:#000864}\n.evt-prob-data-card{background:linear-gradient(135deg,#0f1419,#1a2632);border-radius:16px;padding:40px;ma