x}\n.evt-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .evt-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .evt-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .evt-log-item-label,.et_pb_section .evt-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .evt-log-grid{grid-template-columns:1fr}\n  .evt-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.evt-log-section *{transition:none !important}}\n/* === THAI FONT OVERRIDE (evt-log) === */\n.evt-log-label, .evt-log-title,\n.evt-log-item-label, .evt-log-item-value {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* === REGISTRATION CTA === */\n.evt-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.evt-reg-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.evt-reg-section>*{position:relative;z-index:2}\n.evt-reg-section h2{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#fff;margin:0 0 16px;padding:0}\n.evt-reg-meta{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.85);margin:0 0 32px;padding:0}\n.evt-reg-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;background:#15803d;padding:20px 48px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(21,128,61,0.4)}\n.evt-reg-cta:hover{background:rgb(68,153,100);transform:translateY(-2px);box-shadow:0 8px 24px rgba(21,128,61,0.3)}\n.evt-reg-secondary{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-top:24px;padding:0}\n.evt-reg-secondary a{color:#fff;text-decoration:underline;transition:color 0.3s ease}\n.evt-reg-secondary a:hover{color:#fff}\n\n.et_pb_section .evt-reg-section h2{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .evt-reg-cta{-webkit-font-smoothing:auto !important;line-height:28.8px !important}\n.et_pb_section .evt-reg-meta,.et_pb_section .evt-reg-secondary{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .evt-reg-section h2{font-size:32px}\n  .evt-reg-cta{width:100%;justify-content:center;padding:16px 32px;font-size:16px}\n}\n@media(prefers-reduced-motion:reduce){.evt-reg-section *{transition:none !important}}\n/* === THAI FONT OVERRIDE (evt-reg) === */\n.evt-reg-title, .evt-reg-meta,\n.evt-reg-btn, .evt-reg-secondary {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* === RELATED EVENTS === */\n.evt-rel-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.evt-rel-inner{max-width:1100px;margin:0 auto}\n.evt-rel-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#15803d;margin-bottom:16px}\n.evt-rel-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.evt-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.evt-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.evt-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.evt-rel-card-border{height:4px}\n.evt-rel-card-body{padding:28px}\n.evt-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.evt-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.evt-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.evt-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.evt-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.evt-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.evt-rel-link:hover{opacity:0.8}\n\n.et_pb_section .evt-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .evt-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .evt-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .evt-rel-grid{grid-template-columns:1fr}\n  .evt-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.evt-rel-card{transition:none !important}}\n/* === THAI FONT OVERRIDE (evt-rel) === */\n.evt-rel-label, .evt-rel-title,\n.evt-rel-card-badge, .evt-rel-card-title,\n.evt-rel-card-date, .evt-rel-card-location {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

